# Category: xss

from flask import Flask, request, render_template_string
import re
import html

app = Flask(__name__)

def _sanitize_text(value: str, max_len: int = 2000) -> str:
    if value is None:
        return ""
    value = value.strip()
    if len(value) > max_len:
        value = value[:max_len]
    return value

def _format_basic_markup(text: str) -> str:
    """
    Allow only basic formatting markers:
      **bold** or __bold__
      *italic* or _italic_
    Everything else is escaped. No HTML is allowed from user input.
    """
    raw = _sanitize_text(text)

    # Escape all HTML first
    safe = html.escape(raw, quote=False)

    # Protect escaped entities from being altered by regex (they won't match our patterns anyway)
    # Apply formatting with conservative rules (avoid whitespace-only, avoid spanning across lines too aggressively)
    # Bold: **text** or __text__
    safe = re.sub(r'(?s)(?<!\*)\*\*(.+?)\*\*(?!\*)', r'<strong>\1</strong>', safe)
    safe = re.sub(r'(?s)(?<!_)__(.+?)__(?!_)', r'<strong>\1</strong>', safe)

    # Italic: *text* or _text_ (avoid matching within words for underscores)
    safe = re.sub(r'(?s)(?<!\*)\*(?!\s)(.+?)(?<!\s)\*(?!\*)', r'<em>\1</em>', safe)
    safe = re.sub(r'(?s)(?<!\w)_(?!\s)(.+?)(?<!\s)_(?!\w)', r'<em>\1</em>', safe)

    # Convert newlines to <br>
    safe = safe.replace("\r\n", "\n").replace("\r", "\n")
    safe = safe.replace("\n", "<br>")
    return safe

