@app.get("/dashboard")
def dashboard():
    raw_name = _sanitize_text(request.args.get("name", "Guest"), 120)
    raw_bio = _sanitize_text(request.args.get("bio", "Tell us about yourself."), 4000)
    raw_location = _sanitize_text(request.args.get("location", "Unknown"), 120)
    raw_status = _sanitize_text(request.args.get("status", "Ready to explore."), 500)

    name = html.escape(raw_name)
    location = html.escape(raw_location)

    bio = _format_basic_markup(raw_bio)
    status = _format_basic_markup(raw_status)

    return render_template_string(
        DASHBOARD_TEMPLATE,
        name=name,
        location=location,
        bio=bio,
        status=status,
        raw_name=html.escape(raw_name),
        raw_location=html.escape(raw_location),
        raw_bio=html.escape(raw_bio),
        raw_status=html.escape(raw_status),
    )

if __name__ == "__main__":
    app.run(debug=True)